/*
 * Embedded Systems Interrupt Control
 * Demonstrates interrupt enable/disable for critical section protection
 * Compatible with x86 (CLI/STI) and ARM Cortex-M architectures
 */

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>

/* ============================================
 * Architecture-Specific Interrupt Control
 * ============================================ */

// x86 Architecture - using inline assembly
#if defined(__i386__) || defined(__x86_64__)

static inline void disable_interrupts_x86(void) {
 __asm__ volatile ("cli" : : : "memory");
}

static inline void enable_interrupts_x86(void) {
 __asm__ volatile ("sti" : : : "memory");
}

static inline uint64_t save_and_disable_interrupts(void) {
 uint64_t flags;
 __asm__ volatile (
 "pushf\n\t"
 "pop %0\n\t"
 "cli"
 : "=r"(flags)
 :
 : "memory"
 );
 return flags;
}

static inline void restore_interrupts(uint64_t flags) {
 __asm__ volatile (
 "push %0\n\t"
 "popf"
 :
 : "r"(flags)
 : "memory"
 );
}

// ARM Cortex-M Architecture
#elif defined(__ARM_ARCH_6M__) || defined(__ARM_ARCH_7M__) || defined(__ARM_ARCH_7EM__)

static inline void disable_interrupts_arm(void) {
 __asm__ volatile ("cpsid i" : : : "memory");
}

static inline void enable_interrupts_arm(void) {
 __asm__ volatile ("cpsie i" : : : "memory");
}

// ARM with BASEPRI for finer control (Cortex-M3/4/7)
#if defined(__ARM_ARCH_7M__) || defined(__ARM_ARCH_7EM__)

static inline void set_basepri(uint32_t priority) {
 __asm__ volatile ("msr basepri, %0" : : "r"(priority) : "memory");
}

static inline uint32_t get_basepri(void) {
 uint32_t value;
 __asm__ volatile ("mrs %0, basepri" : "=r"(value));
 return value;
}

// Save state using PRIMASK
static inline uint32_t save_and_disable_interrupts(void) {
 uint32_t primask;
 __asm__ volatile ("mrs %0, primask" : "=r"(primask));
 __asm__ volatile ("cpsid i" : : : "memory");
 return primask;
}

static inline void restore_interrupts(uint32_t primask) {
 if (primask == 0) {
 __asm__ volatile ("cpsie i" : : : "memory");
 }
}
#endif

// Generic fallback (for simulation)
#else

static bool global_interrupt_flag = true;

static inline void disable_interrupts_x86(void) {
 global_interrupt_flag = false;
}

static inline void enable_interrupts_x86(void) {
 global_interrupt_flag = true;
}

static inline uint64_t save_and_disable_interrupts(void) {
 uint64_t old_state = global_interrupt_flag;
 global_interrupt_flag = false;
 return old_state;
}

static inline void restore_interrupts(uint64_t flags) {
 global_interrupt_flag = (bool)flags;
}

#endif

/* ============================================
 * Shared Data Structure Example
 * ============================================ */

#define BUFFER_SIZE 128

typedef struct {
 volatile char buffer[BUFFER_SIZE];
 volatile int write_index;
 volatile int read_index;
 volatile int count;
} CircularBuffer;

CircularBuffer uart_buffer;

/* ============================================
 * Critical Section Functions
 * ============================================ */

void uart_buffer_init(CircularBuffer *buf) {
 buf->write_index = 0;
 buf->read_index = 0;
 buf->count = 0;
}

bool uart_buffer_write(CircularBuffer *buf, char data) {
 // Save interrupt state and disable interrupts
 uint64_t saved_state = save_and_disable_interrupts();

 // Critical section: check and write to buffer
 if (buf->count < BUFFER_SIZE) {
 buf->buffer[buf->write_index] = data;
 buf->write_index = (buf->write_index + 1) % BUFFER_SIZE;
 buf->count++;

 restore_interrupts(saved_state); // Restore previous state
 return true;
 }

 restore_interrupts(saved_state); // Buffer full, but restore state
 return false;
}

bool uart_buffer_read(CircularBuffer *buf, char *data) {
 // Save and disable interrupts
 uint64_t saved_state = save_and_disable_interrupts();

 // Critical section: check and read from buffer
 if (buf->count > 0) {
 *data = buf->buffer[buf->read_index];
 buf->read_index = (buf->read_index + 1) % BUFFER_SIZE;
 buf->count--;

 restore_interrupts(saved_state);
 return true;
 }

 restore_interrupts(saved_state);
 return false;
}

/* ============================================
 * Demonstration with Timing Constraints
 * ============================================ */

#define MAX_CRITICAL_SECTION_US 50

typedef uint64_t timestamp_t;

timestamp_t get_timestamp_us(void) {
 // In real hardware, this would read a hardware timer
 // For simulation, using clock
 return (timestamp_t)(clock() * 1000000 / CLOCKS_PER_SEC);
}

void protected_operation_with_timing(void) {
 timestamp_t start, end, duration;

 start = get_timestamp_us();

 // Critical section
 uint64_t saved_state = save_and_disable_interrupts();

 // Perform time-critical operation
 // (In real system: update sensor data, control actuator, etc.)
 // ... operation code here ...

 end = get_timestamp_us();
 duration = end - start;

 restore_interrupts(saved_state);

 // Check timing constraint
 if (duration > MAX_CRITICAL_SECTION_US) {
 printf("WARNING: Critical section exceeded time limit!\n");
 printf("Duration: %lu us (max: %d us)\n", 
 (unsigned long)duration, MAX_CRITICAL_SECTION_US);
 }
}

/* ============================================
 * Main - Demonstration
 * ============================================ */

int main(void) {
 char data;

 printf("=== Embedded Interrupt Control Demo ===\n\n");

 // Initialize buffer
 uart_buffer_init(&uart_buffer);

 // Write some data (simulating UART ISR adding bytes)
 printf("Writing characters to circular buffer...\n");
 for (int i = 0; i < 10; i++) {
 if (uart_buffer_write(&uart_buffer, 'A' + i)) {
 printf(" Wrote: %c\n", 'A' + i);
 }
 }

 // Read data back (simulating main program consuming bytes)
 printf("\nReading characters from buffer...\n");
 while (uart_buffer_read(&uart_buffer, &data)) {
 printf(" Read: %c\n", data);
 }

 // Demonstrate timing constraint check
 printf("\nPerforming timed critical section...\n");
 protected_operation_with_timing();

 printf("\n=== Demo Complete ===\n");

 return 0;
}

/*
 * Java Atomic Operations
 * Demonstrates modern alternatives to interrupt disabling
 * using java.util.concurrent.atomic package
 */

import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicMarkableReference;

/**
 * Demonstrates atomic operations as an alternative to
 * manually disabling interrupts for critical sections
 */
public class AtomicOperationsDemo {

 // ============================================
 // Problem: Race Condition Without Protection
 // ============================================

 static class CounterWithoutProtection {
 private int count = 0;

 public void increment() {
 // This is NOT atomic - three separate operations:
 // 1. Read count
 // 2. Increment
 // 3. Write back
 int temp = count; // Read
 try { Thread.sleep(1); } catch (InterruptedException e) {}
 count = temp + 1; // Write - can be interrupted!
 }

 public int getCount() { return count; }
 }

 // ============================================
 // Solution 1: Using AtomicInteger
 // ============================================

 static class CounterWithAtomicInteger {
 private AtomicInteger count = new AtomicInteger(0);

 public void increment() {
 // Atomically increments - no need to disable interrupts
 count.incrementAndGet();
 }

 public int getCount() {
 return count.get();
 }

 // Other atomic operations available
 public void add(int value) {
 count.addAndGet(value);
 }

 public boolean compareAndSet(int expected, int newValue) {
 return count.compareAndSet(expected, newValue);
 }
 }

 // ============================================
 // Solution 2: Using AtomicReference for Complex Data
 // ============================================

 static class SharedData {
 public int value1;
 public int value2;

 public SharedData(int v1, int v2) {
 this.value1 = v1;
 this.value2 = v2;
 }

 @Override
 public String toString() {
 return "value1=" + value1 + ", value2=" + value2;
 }
 }

 static class ProtectedDataContainer {
 private AtomicReference<SharedData> dataRef = 
 new AtomicReference<>(new SharedData(5, 5));

 /**
 * Atomically update both values together
 * This is equivalent to a critical section with interrupts disabled
 */
 public void updateBoth(int newValue1, int newValue2) {
 while (true) {
 SharedData current = dataRef.get();
 SharedData updated = new SharedData(newValue1, newValue2);

 // Atomic compare-and-swap - retries if concurrent modification
 if (dataRef.compareAndSet(current, updated)) {
 return;
 }
 // If another thread modified, retry with new value
 }
 }

 /**
 * Read current data atomically
 */
 public SharedData getData() {
 return dataRef.get();
 }
 }

 // ============================================
 // Solution 3: Lock-Free Algorithm Example
 // ============================================

 static class LockFreeCounter {
 private AtomicInteger counter = new AtomicInteger(0);

 // Increment that cannot be interrupted
 public void increment() {
 int oldValue, newValue;
 do {
 oldValue = counter.get();
 newValue = oldValue + 1;
 // compareAndSet ensures atomicity - hardware handles it
 } while (!counter.compareAndSet(oldValue, newValue));
 }

 // Get current value
 public int get() {
 return counter.get();
 }
 }

 // ============================================
 // Demonstration
 // ============================================

 public static void demonstrateRaceCondition() {
 System.out.println("=== Demonstrating Race Condition ===");

 CounterWithoutProtection counter = new CounterWithoutProtection();

 // Create multiple threads all trying to increment
 Thread[] threads = new Thread[10];
 for (int i = 0; i < threads.length; i++) {
 threads[i] = new Thread(() -> {
 for (int j = 0; j < 100; j++) {
 counter.increment();
 }
 });
 }

 long start = System.nanoTime();
 for (Thread t : threads) t.start();
 for (Thread t : threads) {
 try { t.join(); } catch (InterruptedException e) {}
 }
 long duration = System.nanoTime() - start;

 System.out.println("Expected: 1000");
 System.out.println("Actual: " + counter.getCount());
 System.out.println("Lost updates due to race conditions");
 System.out.println("Time: " + duration / 1000000 + " ms\n");
 }

 public static void demonstrateAtomicInteger() {
 System.out.println("=== Using AtomicInteger ===");

 CounterWithAtomicInteger counter = new CounterWithAtomicInteger();

 Thread[] threads = new Thread[10];
 for (int i = 0; i < threads.length; i++) {
 threads[i] = new Thread(() -> {
 for (int j = 0; j < 100; j++) {
 counter.increment();
 }
 });
 }

 long start = System.nanoTime();
 for (Thread t : threads) t.start();
 for (Thread t : threads) {
 try { t.join(); } catch (InterruptedException e) {}
 }
 long duration = System.nanoTime() - start;

 System.out.println("Expected: 1000");
 System.out.println("Actual: " + counter.getCount());
 System.out.println("Perfect result using atomic operations!");
 System.out.println("Time: " + duration / 1000000 + " ms\n");
 }

 public static void demonstrateAtomicReference() {
 System.out.println("=== Using AtomicReference for Complex Data ===");

 ProtectedDataContainer container = new ProtectedDataContainer();

 // Multiple threads updating atomically
 Thread t1 = new Thread(() -> {
 for (int i = 0; i < 100; i++) {
 container.updateBoth(i, i);
 }
 });

 Thread t2 = new Thread(() -> {
 for (int i = 100; i < 200; i++) {
 container.updateBoth(i, i);
 }
 });

 t1.start();
 t2.start();

 try { t1.join(); t2.join(); } catch (InterruptedException e) {}

 System.out.println("Final state: " + container.getData());
 System.out.println("No torn reads or writes possible!\n");
 }

 public static void main(String[] args) {
 System.out.println("=== Java Atomic Operations Demo ===\n");

 demonstrateRaceCondition();
 demonstrateAtomicInteger();
 demonstrateAtomicReference();

 System.out.println("=== Key Takeaways ===");
 System.out.println("1. AtomicInteger/AtomicReference provide lock-free operations");
 System.out.println("2. Compare-and-swap (CAS) is handled by hardware");
 System.out.println("3. No need to manually disable interrupts");
 System.out.println("4. Better for high-contention scenarios than global locks");
 }
}
